function asArray(nodeName) {
  const items = $(nodeName).all();
  if (!items || items.length === 0) return [];
  if (items.length > 1) return items.map(it => it.json);
  const j = items[0].json;
  if (Array.isArray(j)) return j;
  return [j];
}

const bus = asArray('Fetch BU cards');
const precedent = asArray('Fetch Sent precedent');

const precByBU = new Map();
for (const p of (precedent || [])) {
  if (!p.business_unit_id) continue;
  if (!precByBU.has(p.business_unit_id)) precByBU.set(p.business_unit_id, []);
  if (precByBU.get(p.business_unit_id).length < 5) {
    precByBU.get(p.business_unit_id).push(p.job_title);
  }
}

const buSection = bus.map(bu => {
  const prec = precByBU.get(bu.id) || [];
  return [
    `## ${bu.name}`,
    bu.description,
    `Scopes: ${(bu.scopes || []).join(' · ')}`,
    `Keywords: ${(bu.keywords || []).slice(0, 30).join(', ')}`,
    `Good fit: ${bu.good_fit_signals || ''}`,
    `Red flags: ${bu.red_flags || ''}`,
    `Decision: ${bu.decision_logic || ''}`,
    prec.length > 0 ? `Recent Sent precedent: ${prec.join(' · ')}` : 'Recent Sent precedent: (none yet)',
  ].join('\n');
}).join('\n\n---\n\n');

const HARD_EXCLUSIONS = [
  'pure graphic design only (no strategy)',
  'physical product manufacturing',
  'legal services (lawyers, customs/tariff compliance, immigration, contracts)',
  'medical services (clinical, MD, nursing)',
  'academic writing, grant writing for non-profits, non-profit work',
  'civil / mechanical / electrical / aerospace / hardware engineering',
  'embedded systems, firmware, DSP (digital signal processing), radar, RF, IoT hardware',
  'COACHING / TRAINING ROLES (STRICT): if the job title or scope mentions Coach, Trainer, Coaching, Training, Mentor, Enablement, Workshop, Bootcamp, even if it mentions teams, projects, or implementation, IT IS COACHING and must be DISCARDED. The presence of "team", "project", or "implementation" does NOT make it a project job — it is still teaching/coaching.',
  'MICROSOFT ECOSYSTEM (STRICT): Any job involving Microsoft 365, Office 365, Dynamics (any version: 365, NAV, AX, CRM, GP), SharePoint, Power Platform (Power Apps, Power Automate, Power BI as Microsoft admin), Outlook, Teams, Azure AD admin. EVEN IF the integration uses Claude/OpenAI/n8n to connect TO Microsoft, the Microsoft side is the disqualifier. EXCEPTION: Power BI used purely as a dashboarding tool (no Microsoft admin) is OK for Project Management & BI.',
  'SAP INTERNAL (STRICT): Any job involving SAP ABAP, SAP customization, SAP NCo, RFC/BAPI, SAP development inside the platform. EXCEPTION: pulling data FROM SAP to external systems via standard APIs is OK.',
  'PR / MEDIA RELATIONS (STRICT): publicity, press releases, media pitching, journalist outreach, brand ambassador work. The presence of "marketing" or "brand" in the title does NOT override this — if the core work is PR/publicity, DISCARD.',
  'CPA TACTICAL (STRICT): US tax filings, IRS, federal/state tax, audit, late filing, Delaware C-Corp filings, SBA loans, bookkeeping. Even if it mentions financial modeling, if the deliverable is tax compliance work, DISCARD. EXCEPTION: strategic CFO advisory or fundraising-related modeling is OK.',
  'TOOL-SPECIFIC EXCLUSIONS (STRICT): Framer (any mention), Figma (ANY mention — primary or secondary, as deliverable or as tool, even if just listed alongside others), Klaviyo execution-only operator, Etsy listing/SEO optimization, Smartsheet formula help, Shopify theme customization, Wix.',
  'ONE-TIME TACTICAL: single formula fix, urgent quick help, single-day jobs, one-shot audits without strategy.',
  'BROKERAGE / NETWORKING / RELATIONSHIP roles without technical scope (business development manager pure relationship sales, capital markets brokers, M&A intermediaries).',
  'RECRUITING: talent acquisition, HR sourcing, headhunting.',
  'CRYPTO/WEB3 SPECIALIST: blockchain game backend, smart contract dev (unless paired with broader SaaS work).',
  'PURE 3D/VFX/ANIMATION: Blender simulation, VFX production, motion graphics as core deliverable.',
];

const buNameToId = {};
for (const bu of bus) buNameToId[bu.name] = bu.id;

const systemPrompt = [
  'You are a senior qualification analyst for SWL Consulting, an AI-native consulting firm.',
  '',
  'Your job: decide if an incoming Upwork job is a MATCH for SWL.',
  '',
  `Below are SWL's 8 business units. Each card includes scope, keywords, good-fit signals, red flags, decision logic, and recent precedent (real proposals SWL has sent).`,
  '',
  buSection,
  '',
  '---',
  '',
  'HARD EXCLUSIONS (always match=false, score<=10):',
  ...HARD_EXCLUSIONS.map(e => `- ${e}`),
  '',
  'BU-SPECIFIC RULES (always qualify if scope matches, regardless of ticket):',
  '- Power BI / Tableau / Looker dashboard engineering → Project Management & BI',
  '- n8n / Zapier / Make automation → System Integrations or AI & Automation',
  '- Meta Ads / Google Ads / paid social strategy + funnel → Marketing & Brand',
  '- Fractional CFO / COO / GM for SaaS/startups → Finance & Accounting or Business Operations',
  '- Brand design with strategy (not pure execution) → Marketing & Brand',
  '',
  'CRITICAL TICKET POLICY:',
  'Jobs reach you ONLY after passing SQL filter (hourly>$40/h, posted <24h, <=50 proposals). Budget is already validated.',
  'NEVER mention ticket, budget, engagement minimum, hourly rate, underpriced, far below, or pricing in your "reason".',
  'If the scope fits a BU and no hard exclusion applies, you MUST set match=true. Budget is NOT your concern.',
  'If your reason contains any of these forbidden phrases, the output is INVALID and will be rejected.',
  '',
  'AREA ASSIGNMENT: Whenever the job scope plausibly fits one of the 8 BUs, set "area" to that BU name (exactly as listed above), EVEN IF match=false. Only return area=null when scope clearly fits NONE.',
  '',
  'Decision protocol:',
  '1. Read job title + description.',
  '2. Identify BU (if any) -> set area.',
  '3. Check hard exclusions strictly -> if any apply, match=false.',
  '4. Otherwise, weigh good-fit signals, red flags, decision logic, precedent — SCOPE ONLY.',
  '5. match=true when scope fit + no exclusion + plausible precedent.',
  '6. score: 0=miss, 30=weak, 60=plausible, 85+=strong fit with precedent.',
  '7. reason <= 25 words, concrete. Cite signals or precedent. NEVER cite budget/ticket.',
  '',
  'Return ONLY valid JSON, no markdown fences, no prose: { "match": bool, "score": 0-100, "area": <one of the BU names above> | null, "reason": "..." }',
].join('\n');

return { json: { systemPrompt, buNameToId } };

const job = $json;
const systemPrompt = $('Build Classifier System Prompt').first().json.systemPrompt;
const userPrompt = [
  `Job title: ${job.title}`,
  `Industry: ${job.industry || 'n/a'}`,
  '',
  'Description:',
  job.description || '(no description)',
].join('\n');

return { json: { ...job, systemPrompt, userPrompt } };

