const job = $('Build Classifier User Prompt').item.json;
const ai = $json;
const buNameToId = $('Build Classifier System Prompt').first().json.buNameToId;

let parsed;
try {
  const text = (ai.content && ai.content[0] && ai.content[0].text) || '{}';
  const clean = text.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = { match: false, score: 0, area: null, reason: 'parse_error: ' + e.message };
}

const area = (typeof parsed.area === 'string' && parsed.area.length > 0) ? parsed.area : null;
let score = typeof parsed.score === 'number' ? Math.max(0, Math.min(100, Math.round(parsed.score))) : 0;
let match = !!parsed.match;
let reason = parsed.reason || '';
const businessUnitId = area ? (buNameToId[area] || null) : null;

// FORBIDDEN PHRASES: if LLM cites budget/ticket as reason for rejecting,
// the rejection is invalid — auto-qualify when area is assigned.
const FORBIDDEN_BUDGET = [
  /\bticket\b/i,
  /\bbudget\b/i,
  /\bunderpriced\b/i,
  /\bfar\s+below\b/i,
  /\btoo\s+low\b/i,
  /\bengagement\s+minimum/i,
  /\bnon.?viable\b/i,
  /\bunrealistic\s+budget/i,
  /\bhourly\s+rate/i,
  /\bpricing\b/i,
  /\bsub-?\$[0-9]/i,
  /\$[0-9]+\s*(USD|hour|hr|month|week)/i,
];
const forbiddenViolation = FORBIDDEN_BUDGET.some(re => re.test(reason));
if (!match && area && forbiddenViolation) {
  match = true;
  reason = '[forbidden-phrase rescue: LLM cited budget; forced match by scope+area] orig: ' + reason.slice(0, 150);
  if (score < 50) score = 50;
}

const newStatus = match ? 'qualified' : 'discarded';

return { json: {
  job_id: job.id,
  newStatus,
  match,
  score,
  area,
  reason,
  businessUnitId,
}};
